def generate_csv(output_path: str = "dataset/final_eval.csv"):
    """Write the dataset to a CSV file."""
    os.makedirs(os.path.dirname(output_path), exist_ok=True)
    with open(output_path, "w", newline="", encoding="utf-8") as f:
        writer = csv.writer(f)
        writer.writerow(["id", "prompt", "language", "attack_type", "has_pii",
                         "expected_policy", "expected_entities", "source"])
        writer.writerows(DATASET)
    print(f"Dataset written to {output_path} ({len(DATASET)} rows)")

    from collections import Counter
    policies = Counter(row[5] for row in DATASET)
    langs = Counter(row[2] for row in DATASET)
    print("\nPolicy distribution:")
    for p, c in sorted(policies.items()):
        print(f"  {p}: {c}")
    print(f"\nLanguages covered: {len(langs)}")
    for lang, count in sorted(langs.items(), key=lambda x: -x[1])[:15]:
        print(f"  {lang}: {count}")


if __name__ == "__main__":
    generate_csv()
